--FICHERO EJECUCION PARA IR DE LANDING A RAW 

--SCRIPT_AUTOMATICO
--Esto lo ejecuto para la creacion de las tablas en RAW, los STREAMS y las TASKS de cada una de ellas. 

--creacion del esquema de streams y tasks 
USE DATABASE PROYECTO;
USE SCHEMA STREAMS_Y_TASKS;


-- MEDICOS
CREATE TABLE IF NOT EXISTS RAW_NEXTBIO.MEDICOS AS SELECT * FROM LANDING_NEXTBIO.MEDICOS;
CREATE OR REPLACE STREAM STREAM_RAW_NEXTBIO_MEDICOS ON TABLE LANDING_NEXTBIO.MEDICOS APPEND_ONLY = TRUE;
CREATE OR REPLACE TASK TASK_RAW_NEXTBIO_MEDICOS WAREHOUSE = COMPUTE_WH SCHEDULE = '5 MINUTE' WHEN SYSTEM$STREAM_HAS_DATA('STREAM_RAW_NEXTBIO_MEDICOS') AS INSERT INTO RAW_NEXTBIO.MEDICOS SELECT * EXCLUDE (METADATA$ACTION, METADATA$ISUPDATE, METADATA$ROW_ID) FROM STREAM_RAW_NEXTBIO_MEDICOS WHERE METADATA$ACTION = 'INSERT';
ALTER TASK TASK_RAW_NEXTBIO_MEDICOS RESUME;

